import React, { useState } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { GoogleLogin } from '@react-oauth/google';
import axios from 'axios';
import toast from 'react-hot-toast';
import OTPVerification from '../components/OTPVerification';

export default function LoginPage() {
  const [searchParams] = useSearchParams();
  const [showOTP, setShowOTP] = useState(false);
  const [pendingEmail, setPendingEmail] = useState('');
  const [loading, setLoading] = useState(false);

  const handleGoogleSuccess = async (credentialResponse) => {
    setLoading(true);
    try {
      const { data } = await axios.post(
        'http://localhost:8000/api/auth/google/',
        { token: credentialResponse.credential },
        { withCredentials: true }
      );

      // Check if verification is required
      if (data.requires_verification) {
        setPendingEmail(data.email);
        setShowOTP(true);
        toast.success('Verification code sent to your email!');
      } else {
        // Already verified user - login directly
        localStorage.setItem('access_token', data.access);
        localStorage.setItem('user', JSON.stringify(data.user));
        toast.success(`Welcome back, ${data.user.full_name || data.user.email}!`);
        window.location.href = searchParams.get('next') || '/';
      }
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Google login failed.');
    } finally {
      setLoading(false);
    }
  };

  const handleOTPVerified = (userData) => {
    localStorage.setItem('access_token', userData.access);
    localStorage.setItem('user', JSON.stringify(userData.user));
    toast.success('Email verified successfully!');
    window.location.href = searchParams.get('next') || '/';
  };

  const handleGoogleError = () => {
    toast.error('Google sign-in failed. Please try again.');
  };

  // Show OTP verification screen
  if (showOTP) {
    return (
      <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #0a1e3d 0%, #1a3a5c 100%)' }}>
        <div style={{ background: 'white', borderRadius: 20, padding: 40, width: '100%', maxWidth: 400 }}>
          <OTPVerification 
            email={pendingEmail}
            onVerified={handleOTPVerified}
            onBack={() => setShowOTP(false)}
          />
        </div>
      </div>
    );
  }

  // Show login screen
  return (
    <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #0a1e3d 0%, #1a3a5c 100%)' }}>
      <div style={{ background: 'white', borderRadius: 20, padding: 48, width: '100%', maxWidth: 440, textAlign: 'center' }}>
        <Link to="/" style={{ textDecoration: 'none' }}>
          <h1 style={{ color: '#0a1e3d', marginBottom: 10, fontSize: '1.8rem' }}>Grand Azure</h1>
          <p style={{ color: '#d4af37', letterSpacing: '2px', marginBottom: 30, fontSize: '0.65rem' }}>HOTEL & RESORT</p>
        </Link>

        <h2 style={{ fontSize: '1.8rem', marginBottom: 8 }}>Welcome Back</h2>
        <p style={{ color: '#666', marginBottom: 32 }}>Sign in with your Google account</p>

        <div style={{ display: 'flex', justifyContent: 'center' }}>
          <GoogleLogin
            onSuccess={handleGoogleSuccess}
            onError={handleGoogleError}
            theme="outline"
            size="large"
            width="360"
            text="signin_with"
            shape="rectangular"
          />
        </div>

        {loading && <p style={{ marginTop: 20, color: '#666' }}>Processing...</p>}
      </div>
    </div>
  );
}
